-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_profiles WITH (security_invoker = ON) AS
SELECT
  t.profiles_id,                                                                -- Primary key (auto-synthesized: Profiles had no field named 'Id' or ending in 'Id').
  calc_profiles_name(t.profiles_id) AS name,                                    -- Logical key for the profile, a slug of the account key. Maps to the per-user identity in the substrate.
  t.account_key,                                                                -- Stable per-user identity key. Maps to user_id in the generated schema. Owned rows reference this value through their Owner relationship.
  t.display_name,                                                               -- Friendly display name shown in the app. Default Liz. Maps to profile.display_name.
  t.tagline,                                                                    -- Personal tagline. Default Illuminating Life, Legacy, and Love. Maps to profile.tagline.
  t.weekly_warmup_goal,                                                         -- Target number of hellos per week, shown as encouragement, never a backlog. Default 4. Maps to profile.weekly_warmup_goal. See GovernanceRules R4.
  t.warm_threshold_days,                                                        -- A person stays Warm within this many days of the last hello. Default 14. Maps to profile.warm_threshold_days. See GovernanceRules R2.
  t.cooling_threshold_days,                                                     -- A person is Cooling up to this many days since the last hello, then Cold beyond it. Default 30. Maps to profile.cooling_threshold_days. See GovernanceRules R2.
  t.morning_warmup_count,                                                       -- How many people the Today screen surfaces each morning, one at a time. Default 3. Maps to profile.morning_warmup_count. See GovernanceRules R3.
  t.week_start,                                                                 -- Anchor for the weekly count, set to the most recent Monday. Maps to profile.week_start. See GovernanceRules R4.
  t.week_count,                                                                 -- Hellos logged since WeekStart, maintained by the app and reset each Monday. Default 0. Maps to profile.week_count.
  t.people,                                                                     -- The people owned by this profile.
  t.facilities,                                                                 -- The facilities owned by this profile.
  t.captures,                                                                   -- The captures owned by this profile.
  t.o_auth_tokens,                                                              -- The server-side OAuth tokens owned by this profile.
  calc_profiles_count_of_people(t.profiles_id) AS count_of_people,              -- Number of people in this profile's warm network.
  calc_profiles_count_of_facilities(t.profiles_id) AS count_of_facilities,      -- Number of target facilities owned by this profile.
  calc_profiles_count_of_captures(t.profiles_id) AS count_of_captures           -- Number of captures owned by this profile.
FROM profiles t;

